package loopingClass;

public class OddEvenNumbers {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		//even numbers 
	    int i=0;
	    System.out.print("/nEven Numbers ");
	    while(i<=10) {
	    System.out.print((i+=2)+",");
	    }
	    
	    //Odd Numbers 
	     i=1;
	    System.out.print("/nOdd Numbers ");
	    while(i<=10) {
	    System.out.print((i+=2)+",");
	    }
	}

}
